phase1.code:
// ---- Simple interface ----
interface Drivable {
    fun drive()
    fun stop()
}

// ---- Interface with default implementation ----
interface Soundable {
    // Abstract method (must be implemented)
    fun makeSound(): String

    // Default implementation
    fun describe(): String {
        return "This makes sound: ${makeSound()}"
    }
}

// ---- Interface with properties ----
interface Identifiable {
    val id: Int
    val description: String
        get() = "ID: $id"
}

// ---- Implementing multiple interfaces ----
class Car(
    val brand: String,
    override val id: Int
) : Drivable, Soundable, Identifiable {
    override fun drive() {
        println("$brand is driving")
    }

    override fun stop() {
        println("$brand has stopped")
    }

    override fun makeSound(): String {
        return "Vroom! Vroom!"
    }

    override fun describe(): String {
        return "$brand car: ${super.describe()}"
    }
}

// ---- Interface with properties ----
interface Configurable {
    val maxSpeed: Int
    fun configure() {
        println("Configured with max speed: $maxSpeed")
    }
}

class SportsCar(
    val brand: String,
    override val maxSpeed: Int,
    override val id: Int
) : Drivable, Soundable, Identifiable, Configurable {
    override fun drive() {
        println("$brand sports car accelerating!")
    }

    override fun stop() {
        println("$brand sports car braking!")
    }

    override fun makeSound(): String {
        return "SCREEEEECH!"
    }
}

// ---- Interface for data classes ----
interface Printable {
    fun print()
}

data class Person(
    val name: String,
    val age: Int
) : Printable {
    override fun print() {
        println("Person: $name, $age years old")
    }
}

// ---- Fun interface (SAM conversion) ----
fun interface Logger {
    fun log(message: String)
}

// ---- Using interfaces ----
fun main() {
    // ---- Single interface ----
    val car = Car("Toyota", 1)
    car.drive()
    car.stop()
    println(car.makeSound())
    println(car.describe())
    println(car.description)

    // ---- Multiple interfaces ----
    val sportsCar = SportsCar("Ferrari", 350, 2)
    sportsCar.drive()
    sportsCar.stop()
    println(sportsCar.makeSound())
    sportsCar.configure()

    // ---- Polymorphism with interfaces ----
    val drivables: List<Drivable> = listOf(car, sportsCar)
    for (d in drivables) {
        d.drive()
    }

    val soundables: List<Soundable> = listOf(car, sportsCar)
    for (s in soundables) {
        println(s.describe())
    }

    // ---- Data class with interface ----
    val person = Person("Alice", 30)
    person.print()

    // ---- Functional interface ----
    val logger = Logger { message ->
        println("LOG: $message")
    }
    logger.log("Hello, Kotlin!")

    // ---- SAM conversion with lambda ----
    val logger2 = Logger { println("LOG2: $it") }
    logger2.log("Hello again!")
}

